mapper.select:
SELECT * FROM appointment a
WHERE a.visitor_id = #{visitorId}
  AND a.expected_end_time < #{beforeTime}
  AND a.status = 6
  AND NOT EXISTS (
      SELECT 1 FROM access_log al
      WHERE al.appointment_id = a.appointment_id AND al.access_type = 1
  )
ORDER BY a.expected_end_time DESC LIMIT 1

SELECT COUNT(1) FROM appointment a
WHERE a.status = 6
  AND a.expected_end_time >= #{start}
  AND a.expected_end_time < #{end}
  AND NOT EXISTS (
      SELECT 1 FROM access_log al
      WHERE al.appointment_id = a.appointment_id AND al.access_type = 1
  )
